class Solution:
    def numberOfWays(self, n: int, x: int) -> int:
        MOD = 10**9 + 7
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            j = 1
            while j ** x <= i:
                dp[i] = (dp[i] + dp[i - j ** x]) % MOD
                j += 1
        return dp[n]
